async (page) => {
  // Walk north in steps
  const clickTile = (x, y) => page.evaluate(({x, y}) => JSON.stringify(window.__clickTile(x, y)), {x, y});

  await clickTile(216, 114);
  await page.waitForTimeout(6000);

  const pos = await page.evaluate(() => {
    const s = window.__latestGameState;
    return JSON.stringify({pos: s.player_position});
  });
  return pos;
}
